/**
 * CSV Parser Library for TypeScript
 * Handles parsing, type coercion, filtering, and aggregation
 */

export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

/**
 * Represents the result of parsing CSV data with methods for filtering and aggregation
 */
export class CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: ParseError[];

  constructor(
    rows: Array<Record<string, any>>,
    headers: string[],
    errors: ParseError[] = []
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(
    predicate: (row: Record<string, any>, index: number) => boolean
  ): CSVResult {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum numeric values in a column
   */
  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === 'number' ? value : parseFloat(value);
      return isNaN(num) ? acc : acc + num;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    const validValues = this.rows
      .map((row) => {
        const value = row[column];
        const num = typeof value === 'number' ? value : parseFloat(value);
        return isNaN(num) ? null : num;
      })
      .filter((val) => val !== null) as number[];

    if (validValues.length === 0) return 0;
    const sum = validValues.reduce((acc, val) => acc + val, 0);
    return sum / validValues.length;
  }

  /**
   * Count total rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column: string): Map<any, Array<Record<string, any>>> {
    const groups = new Map<any, Array<Record<string, any>>>();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }

    return groups;
  }
}

/**
 * Parse a value to its appropriate type (number, boolean, null, or string)
 */
function coerceType(value: string): any {
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for number
  const num = parseFloat(value);
  if (!isNaN(num) && value.trim() !== '') {
    // Check if it's an integer or float
    return Number.isInteger(num) ? parseInt(value, 10) : num;
  }

  // Return as string
  return value;
}

/**
 * Parse a CSV string into rows, respecting quoted fields and escaped quotes
 */
function parseCSVLines(
  input: string,
  delimiter: string,
  quoteChar: string,
  lineSeparator: string
): string[][] {
  const rows: string[][] = [];
  let currentLine: string[] = [];
  let currentField = '';
  let insideQuotes = false;
  let i = 0;

  while (i < input.length) {
    const char = input[i];
    const nextChar = input[i + 1];

    if (char === quoteChar) {
      if (insideQuotes && nextChar === quoteChar) {
        // Escaped quote - add one quote to field
        currentField += quoteChar;
        i += 2;
        continue;
      } else {
        // Toggle quote state
        insideQuotes = !insideQuotes;
        i++;
        continue;
      }
    }

    if (!insideQuotes) {
      // Check for line separator
      if (input.substr(i, lineSeparator.length) === lineSeparator) {
        if (currentField !== '' || currentLine.length > 0) {
          currentLine.push(currentField);
        }
        if (currentLine.length > 0) {
          rows.push(currentLine);
        }
        currentLine = [];
        currentField = '';
        i += lineSeparator.length;
        continue;
      }

      // Check for delimiter
      if (char === delimiter) {
        currentLine.push(currentField);
        currentField = '';
        i++;
        continue;
      }
    }

    currentField += char;
    i++;
  }

  // Add last field and line
  if (currentField !== '' || currentLine.length > 0) {
    currentLine.push(currentField);
  }
  if (currentLine.length > 0) {
    rows.push(currentLine);
  }

  return rows;
}

/**
 * Main CSV parsing function
 */
export function parseCSV(
  input: string,
  options: CSVOptions = {}
): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  // Handle empty input
  if (input.trim() === '') {
    return new CSVResult([], [], []);
  }

  // Parse the CSV into raw rows
  const rawRows = parseCSVLines(input, delimiter, quoteChar, lineSeparator);

  if (rawRows.length === 0) {
    return new CSVResult([], [], []);
  }

  // Extract headers from first row
  const headers = rawRows[0];
  const rows: Array<Record<string, any>> = [];
  const errors: ParseError[] = [];

  // Parse data rows
  for (let rowIndex = 1; rowIndex < rawRows.length; rowIndex++) {
    const rawRow = rawRows[rowIndex];

    try {
      // Check for malformed row
      if (rawRow.length !== headers.length) {
        errors.push({
          row: rowIndex,
          message: `Expected ${headers.length} columns, got ${rawRow.length}`,
        });
        continue;
      }

      const row: Record<string, any> = {};
      for (let colIndex = 0; colIndex < headers.length; colIndex++) {
        const header = headers[colIndex];
        const value = rawRow[colIndex];
        row[header] = coerceType(value);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: rowIndex,
        message: error instanceof Error ? error.message : 'Unknown error',
      });
    }
  }

  return new CSVResult(rows, headers, errors);
}

/**
 * Comprehensive test suite for CSV Parser
 */

import { parseCSV, CSVResult } from './csv-parser';

// Test utilities
function assertEqual<T>(actual: T, expected: T, message: string) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertTrue(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertFalse(condition: boolean, message: string) {
  if (condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertArrayEquals(
  actual: any[],
  expected: any[],
  message: string
) {
  if (actual.length !== expected.length) {
    throw new Error(
      `Assertion failed: ${message} - Array length mismatch. Expected ${expected.length}, got ${actual.length}`
    );
  }
  for (let i = 0; i < actual.length; i++) {
    if (JSON.stringify(actual[i]) !== JSON.stringify(expected[i])) {
      throw new Error(
        `Assertion failed: ${message} - Element at index ${i} mismatch.\nExpected: ${JSON.stringify(expected[i])}\nActual: ${JSON.stringify(actual[i])}`
      );
    }
  }
}

function assertThrows(fn: () => void, message: string) {
  try {
    fn();
    throw new Error(`Assertion failed: ${message} - Expected error to be thrown`);
  } catch (e) {
    // Expected
  }
}

// Test suite
console.log('Starting CSV Parser Tests...\n');

// Test 1: Basic parsing with headers
console.log('Test 1: Basic parsing with headers');
{
  const csv = `name,age,email
John,30,john@example.com
Jane,25,jane@example.com`;

  const result = parseCSV(csv);
  assertEqual(result.headers, ['name', 'age', 'email'], 'Headers should be parsed correctly');
  assertEqual(result.rows.length, 2, 'Should have 2 data rows');
  assertEqual(result.rows[0], { name: 'John', age: 30, email: 'john@example.com' }, 'First row should be parsed correctly');
  assertEqual(result.rows[1], { name: 'Jane', age: 25, email: 'jane@example.com' }, 'Second row should be parsed correctly');
  assertEqual(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Passed\n');
}

// Test 2: Quoted fields with commas
console.log('Test 2: Quoted fields with commas');
{
  const csv = `name,address,phone
John,"123 Main St, Apt 4",555-1234
Jane,"456 Oak Ave, Suite 100",555-5678`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].address, '123 Main St, Apt 4', 'Should handle commas inside quoted fields');
  assertEqual(result.rows[1].address, '456 Oak Ave, Suite 100', 'Should handle commas inside quoted fields for second row');
  assertEqual(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Passed\n');
}

// Test 3: Escaped quotes within quoted fields
console.log('Test 3: Escaped quotes within quoted fields');
{
  const csv = `name,quote
John,"He said ""Hello"""
Jane,"She replied ""Hi there"""`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].quote, 'He said "Hello"', 'Should handle escaped quotes');
  assertEqual(result.rows[1].quote, 'She replied "Hi there"', 'Should handle escaped quotes in second row');
  assertEqual(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Passed\n');
}

// Test 4: Type coercion - integers
console.log('Test 4: Type coercion - integers');
{
  const csv = `name,count
Item1,42
Item2,100`;

  const result = parseCSV(csv);
  assertEqual(typeof result.rows[0].count, 'number', 'Integer should be coerced to number');
  assertEqual(result.rows[0].count, 42, 'Integer value should be correct');
  assertEqual(result.rows[1].count, 100, 'Second integer value should be correct');
  console.log('✓ Passed\n');
}

// Test 5: Type coercion - floats
console.log('Test 5: Type coercion - floats');
{
  const csv = `name,price
Item1,19.99
Item2,9.50`;

  const result = parseCSV(csv);
  assertEqual(typeof result.rows[0].price, 'number', 'Float should be coerced to number');
  assertEqual(result.rows[0].price, 19.99, 'Float value should be correct');
  assertEqual(result.rows[1].price, 9.50, 'Second float value should be correct');
  console.log('✓ Passed\n');
}

// Test 6: Type coercion - booleans
console.log('Test 6: Type coercion - booleans');
{
  const csv = `name,active,inactive
Item1,true,false
Item2,True,FALSE
Item3,TRUE,FaLsE`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].active, true, 'Lowercase "true" should be coerced to boolean');
  assertEqual(result.rows[0].inactive, false, 'Lowercase "false" should be coerced to boolean');
  assertEqual(result.rows[1].active, true, 'Capitalized "True" should be coerced to boolean');
  assertEqual(result.rows[1].inactive, false, 'Capitalized "FALSE" should be coerced to boolean');
  assertEqual(result.rows[2].active, true, 'Mixed case "TRUE" should be coerced to boolean');
  assertEqual(result.rows[2].inactive, false, 'Mixed case "FaLsE" should be coerced to boolean');
  console.log('✓ Passed\n');
}

// Test 7: Type coercion - null values
console.log('Test 7: Type coercion - null values');
{
  const csv = `name,value,empty,explicit_null
Item1,test,,null
Item2,data,,NULL`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].empty, null, 'Empty string should be coerced to null');
  assertEqual(result.rows[0].explicit_null, null, 'String "null" should be coerced to null');
  assertEqual(result.rows[1].explicit_null, null, 'String "NULL" should be coerced to null');
  console.log('✓ Passed\n');
}

// Test 8: Type coercion - strings
console.log('Test 8: Type coercion - strings');
{
  const csv = `name,text
Item1,hello
Item2,123abc`;

  const result = parseCSV(csv);
  assertEqual(typeof result.rows[0].text, 'string', 'String should remain as string');
  assertEqual(result.rows[0].text, 'hello', 'String value should be correct');
  assertEqual(result.rows[1].text, '123abc', 'Alphanumeric string should not be converted');
  console.log('✓ Passed\n');
}

// Test 9: Custom delimiter (semicolon)
console.log('Test 9: Custom delimiter (semicolon)');
{
  const csv = `name;age;email
John;30;john@example.com
Jane;25;jane@example.com`;

  const result = parseCSV(csv, { delimiter: ';' });
  assertEqual(result.headers, ['name', 'age', 'email'], 'Headers should use custom delimiter');
  assertEqual(result.rows[0].name, 'John', 'Data should use custom delimiter');
  assertEqual(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Passed\n');
}

// Test 10: Custom quote character
console.log('Test 10: Custom quote character');
{
  const csv = `name,address,phone
John,'123 Main St, Apt 4',555-1234
Jane,'456 Oak Ave, Suite 100',555-5678`;

  const result = parseCSV(csv, { quoteChar: "'" });
  assertEqual(result.rows[0].address, '123 Main St, Apt 4', 'Should handle single quote fields');
  assertEqual(result.errors.length, 0, 'Should have no parsing errors');
  console.log('✓ Passed\n');
}

// Test 11: Custom line separator
console.log('Test 11: Custom line separator');
{
  const csv = `name,age,email\rJohn,30,john@example.com\rJane,25,jane@example.com`;

  const result = parseCSV(csv, { lineSeparator: '\r' });
  assertEqual(result.headers, ['name', 'age', 'email'], 'Headers should use custom line separator');
  assertEqual(result.rows.length, 2, 'Should have 2 data rows with custom line separator');
  assertEqual(result.rows[0].name, 'John', 'Data should use custom line separator');
  console.log('✓ Passed\n');
}

// Test 12: Malformed row error handling - wrong column count
console.log('Test 12: Malformed row error handling - wrong column count');
{
  const csv = `name,age,email
John,30,john@example.com
Jane,25`;

  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, 'Should only include valid rows');
  assertEqual(result.errors.length, 1, 'Should collect error for malformed row');
  assertEqual(result.errors[0].row, 2, 'Error should reference the correct row number');
  assertTrue(result.errors[0].message.includes('Expected 3 columns'), 'Error message should describe the issue');
  console.log('✓ Passed\n');
}

// Test 13: Filter functionality
console.log('Test 13: Filter functionality');
{
  const csv = `name,age,email
John,30,john@example.com
Jane,25,jane@example.com
Bob,35,bob@example.com`;

  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.age > 25);
  assertEqual(filtered.rows.length, 2, 'Filter should return 2 rows');
  assertEqual(filtered.rows[0].name, 'John', 'First filtered row should be John');
  assertEqual(filtered.rows[1].name, 'Bob', 'Second filtered row should be Bob');
  assertEqual(filtered.headers, result.headers, 'Filtered result should have same headers');
  console.log('✓ Passed\n');
}

// Test 14: Filter with index
console.log('Test 14: Filter with index');
{
  const csv = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(csv);
  const filtered = result.filter((row, index) => index > 0);
  assertEqual(filtered.rows.length, 2, 'Filter using index should work correctly');
  assertEqual(filtered.rows[0].name, 'Jane', 'First row after filter should be Jane');
  assertEqual(filtered.rows[1].name, 'Bob', 'Second row after filter should be Bob');
  console.log('✓ Passed\n');
}

// Test 15: Sum aggregation
console.log('Test 15: Sum aggregation');
{
  const csv = `name,amount
Item1,100
Item2,200
Item3,300`;

  const result = parseCSV(csv);
  const sum = result.sum('amount');
  assertEqual(sum, 600, 'Sum should calculate correctly');
  console.log('✓ Passed\n');
}

// Test 16: Sum with mixed types (should skip non-numeric)
console.log('Test 16: Sum with mixed types');
{
  const csv = `name,value
Item1,100
Item2,not_a_number
Item3,200`;

  const result = parseCSV(csv);
  const sum = result.sum('value');
  assertEqual(sum, 300, 'Sum should ignore non-numeric values');
  console.log('✓ Passed\n');
}

// Test 17: Average aggregation
console.log('Test 17: Average aggregation');
{
  const csv = `name,score
Student1,90
Student2,80
Student3,100`;

  const result = parseCSV(csv);
  const avg = result.average('score');
  assertEqual(avg, 90, 'Average should calculate correctly');
  console.log('✓ Passed\n');
}

// Test 18: Average with floats
console.log('Test 18: Average with floats');
{
  const csv = `name,value
A,1.5
B,2.5
C,3.0`;

  const result = parseCSV(csv);
  const avg = result.average('value');
  assertEqual(Math.round(avg * 10) / 10, 2.3, 'Average should handle floats');
  console.log('✓ Passed\n');
}

// Test 19: Count aggregation
console.log('Test 19: Count aggregation');
{
  const csv = `name,age
John,30
Jane,25
Bob,35
Alice,28`;

  const result = parseCSV(csv);
  const count = result.count();
  assertEqual(count, 4, 'Count should return correct number of rows');
  console.log('✓ Passed\n');
}

// Test 20: GroupBy aggregation
console.log('Test 20: GroupBy aggregation');
{
  const csv = `name,department
John,Sales
Jane,Engineering
Bob,Sales
Alice,Engineering`;

  const result = parseCSV(csv);
  const groups = result.groupBy('department');
  assertEqual(groups.size, 2, 'GroupBy should create 2 groups');
  assertTrue(groups.has('Sales'), 'Should have Sales group');
  assertTrue(groups.has('Engineering'), 'Should have Engineering group');
  assertEqual(groups.get('Sales')!.length, 2, 'Sales group should have 2 rows');
  assertEqual(groups.get('Engineering')!.length, 2, 'Engineering group should have 2 rows');
  console.log('✓ Passed\n');
}

// Test 21: GroupBy with null values
console.log('Test 21: GroupBy with null values');
{
  const csv = `name,category
Item1,A
Item2,
Item3,A
Item4,`;

  const result = parseCSV(csv);
  const groups = result.groupBy('category');
  assertTrue(groups.has('A'), 'Should have group A');
  assertTrue(groups.has(null), 'Should have null group');
  assertEqual(groups.get('A')!.length, 2, 'Group A should have 2 rows');
  assertEqual(groups.get(null)!.length, 2, 'Null group should have 2 rows');
  console.log('✓ Passed\n');
}

// Test 22: Empty input
console.log('Test 22: Empty input');
{
  const result = parseCSV('');
  assertEqual(result.rows.length, 0, 'Empty input should return no rows');
  assertEqual(result.headers.length, 0, 'Empty input should return no headers');
  assertEqual(result.errors.length, 0, 'Empty input should have no errors');
  console.log('✓ Passed\n');
}

// Test 23: Single column
console.log('Test 23: Single column');
{
  const csv = `name
John
Jane
Bob`;

  const result = parseCSV(csv);
  assertEqual(result.headers, ['name'], 'Should handle single column');
  assertEqual(result.rows.length, 3, 'Should have 3 data rows');
  assertEqual(result.rows[0].name, 'John', 'Single column data should be correct');
  console.log('✓ Passed\n');
}

// Test 24: Single row (header only)
console.log('Test 24: Single row (header only)');
{
  const csv = `name,age,email`;

  const result = parseCSV(csv);
  assertEqual(result.headers, ['name', 'age', 'email'], 'Should parse headers');
  assertEqual(result.rows.length, 0, 'Should have no data rows');
  console.log('✓ Passed\n');
}

// Test 25: Very long field
console.log('Test 25: Very long field');
{
  const longText = 'A'.repeat(10000);
  const csv = `name,description
Item1,"${longText}"`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].description.length, 10000, 'Should handle very long fields');
  console.log('✓ Passed\n');
}

// Test 26: Whitespace handling
console.log('Test 26: Whitespace handling');
{
  const csv = `name,age
  John  ,  30  
Jane,25`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].name, '  John  ', 'Should preserve leading/trailing whitespace');
  assertEqual(result.rows[0].age, 30, 'Should still coerce to number');
  console.log('✓ Passed\n');
}

// Test 27: Quoted empty field
console.log('Test 27: Quoted empty field');
{
  const csv = `name,middle,last
John,"",Doe
Jane,"",Smith`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].middle, null, 'Empty quoted field should be converted to null');
  console.log('✓ Passed\n');
}

// Test 28: Multiple escaped quotes
console.log('Test 28: Multiple escaped quotes');
{
  const csv = `name,text
Item1,"""quoted"""
Item2,"say ""hello"" and ""goodbye"""`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].text, '"quoted"', 'Should handle multiple escaped quotes');
  assertEqual(result.rows[1].text, 'say "hello" and "goodbye"', 'Should handle multiple escaped quotes in longer text');
  console.log('✓ Passed\n');
}

// Test 29: Newlines in quoted fields (CRLF)
console.log('Test 29: Newlines in quoted fields');
{
  const csv = `name,description\nJohn,"Line1\nLine2"\nJane,"Single line"`;

  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, 'Should handle newlines in quoted fields');
  assertEqual(result.rows[0].description, 'Line1\nLine2', 'Should preserve newlines in quoted fields');
  console.log('✓ Passed\n');
}

// Test 30: Mixed delimiters with quotes
console.log('Test 30: Mixed delimiters with quotes');
{
  const csv = `name;address;phone
John;"123 Main; Suite 1";555-1234
Jane;"456 Oak; Apt 5";555-5678`;

  const result = parseCSV(csv, { delimiter: ';' });
  assertEqual(result.rows[0].address, '123 Main; Suite 1', 'Should handle quoted delimiter inside quoted field');
  console.log('✓ Passed\n');
}

// Test 31: Numeric boolean distinction
console.log('Test 31: Numeric boolean distinction');
{
  const csv = `id,value,is_active
1,100,true
2,0,false
3,false,true`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].value, 100, 'Numeric values should not be confused with booleans');
  assertEqual(result.rows[0].is_active, true, 'String "true" should be boolean');
  assertEqual(result.rows[2].value, false, 'String "false" should be boolean even if looks numeric');
  console.log('✓ Passed\n');
}

// Test 32: Filter chaining
console.log('Test 32: Filter chaining');
{
  const csv = `name,age,department
John,30,Sales
Jane,25,Engineering
Bob,35,Sales
Alice,28,Engineering`;

  const result = parseCSV(csv);
  const filtered = result
    .filter((row) => row.department === 'Sales')
    .filter((row) => row.age > 25);

  assertEqual(filtered.rows.length, 2, 'Chained filters should work');
  assertEqual(filtered.rows[0].name, 'John', 'First result should be John');
  assertEqual(filtered.rows[1].name, 'Bob', 'Second result should be Bob');
  console.log('✓ Passed\n');
}

// Test 33: Aggregation on filtered data
console.log('Test 33: Aggregation on filtered data');
{
  const csv = `name,department,salary
John,Sales,50000
Jane,Engineering,75000
Bob,Sales,55000
Alice,Engineering,80000`;

  const result = parseCSV(csv);
  const salesData = result.filter((row) => row.department === 'Sales');
  const sum = salesData.sum('salary');

  assertEqual(sum, 105000, 'Aggregation on filtered data should work');
  console.log('✓ Passed\n');
}

// Test 34: Headers with special characters
console.log('Test 34: Headers with special characters');
{
  const csv = `user-name,email@domain,age_years
John,john@example.com,30
Jane,jane@example.com,25`;

  const result = parseCSV(csv);
  assertEqual(result.headers, ['user-name', 'email@domain', 'age_years'], 'Should handle special characters in headers');
  assertEqual(result.rows[0]['user-name'], 'John', 'Should access columns with special characters');
  console.log('✓ Passed\n');
}

// Test 35: Unicode characters
console.log('Test 35: Unicode characters');
{
  const csv = `name,city
José,São Paulo
François,Paris
李明,北京`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0].name, 'José', 'Should handle Unicode characters');
  assertEqual(result.rows[1].city, 'Paris', 'Should handle Unicode in data');
  assertEqual(result.rows[2].name, '李明', 'Should handle non-Latin Unicode');
  console.log('✓ Passed\n');
}

// Test 36: Sum on filtered data
