/**
 * CSV Parser Library for JavaScript/TypeScript
 * Handles parsing, type coercion, filtering, and aggregation
 */

/**
 * Represents the result of parsing CSV data with methods for filtering and aggregation
 */
class CSVResult {
  constructor(rows = [], headers = [], errors = []) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(predicate) {
    const filtered = this.rows.filter(predicate);
    return new CSVResult(filtered, this.headers, this.errors);
  }

  /**
   * Sum numeric values in a column
   */
  sum(column) {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === 'number' ? value : parseFloat(value);
      return isNaN(num) ? acc : acc + num;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column) {
    const validValues = this.rows
      .map((row) => {
        const value = row[column];
        const num = typeof value === 'number' ? value : parseFloat(value);
        return isNaN(num) ? null : num;
      })
      .filter((val) => val !== null);

    if (validValues.length === 0) return 0;
    const sum = validValues.reduce((acc, val) => acc + val, 0);
    return sum / validValues.length;
  }

  /**
   * Count total rows
   */
  count() {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column) {
    const groups = new Map();

    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key).push(row);
    }

    return groups;
  }
}

/**
 * Parse a value to its appropriate type (number, boolean, null, or string)
 */
function coerceType(value) {
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Check for boolean
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Check for number
  const num = parseFloat(value);
  if (!isNaN(num) && value.trim() !== '') {
    // Check if it's an integer or float
    return Number.isInteger(num) ? parseInt(value, 10) : num;
  }

  // Return as string
  return value;
}

/**
 * Parse a CSV string into rows, respecting quoted fields and escaped quotes
 */
function parseCSVLines(input, delimiter, quoteChar, lineSeparator) {
  const rows = [];
  let currentLine = [];
  let currentField = '';
  let insideQuotes = false;
  let i = 0;

  while (i < input.length) {
    const char = input[i];
    const nextChar = input[i + 1];

    if (char === quoteChar) {
      if (insideQuotes && nextChar === quoteChar) {
        // Escaped quote - add one quote to field
        currentField += quoteChar;
        i += 2;
        continue;
      } else {
        // Toggle quote state
        insideQuotes = !insideQuotes;
        i++;
        continue;
      }
    }

    if (!insideQuotes) {
      // Check for line separator
      if (input.substr(i, lineSeparator.length) === lineSeparator) {
        if (currentField !== '' || currentLine.length > 0) {
          currentLine.push(currentField);
        }
        if (currentLine.length > 0) {
          rows.push(currentLine);
        }
        currentLine = [];
        currentField = '';
        i += lineSeparator.length;
        continue;
      }

      // Check for delimiter
      if (char === delimiter) {
        currentLine.push(currentField);
        currentField = '';
        i++;
        continue;
      }
    }

    currentField += char;
    i++;
  }

  // Add last field and line
  if (currentField !== '' || currentLine.length > 0) {
    currentLine.push(currentField);
  }
  if (currentLine.length > 0) {
    rows.push(currentLine);
  }

  return rows;
}

/**
 * Main CSV parsing function
 */
function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  // Handle empty input
  if (input.trim() === '') {
    return new CSVResult([], [], []);
  }

  // Parse the CSV into raw rows
  const rawRows = parseCSVLines(input, delimiter, quoteChar, lineSeparator);

  if (rawRows.length === 0) {
    return new CSVResult([], [], []);
  }

  // Extract headers from first row
  const headers = rawRows[0];
  const rows = [];
  const errors = [];

  // Parse data rows
  for (let rowIndex = 1; rowIndex < rawRows.length; rowIndex++) {
    const rawRow = rawRows[rowIndex];

    try {
      // Check for malformed row
      if (rawRow.length !== headers.length) {
        errors.push({
          row: rowIndex,
          message: `Expected ${headers.length} columns, got ${rawRow.length}`,
        });
        continue;
      }

      const row = {};
      for (let colIndex = 0; colIndex < headers.length; colIndex++) {
        const header = headers[colIndex];
        const value = rawRow[colIndex];
        row[header] = coerceType(value);
      }

      rows.push(row);
    } catch (error) {
      errors.push({
        row: rowIndex,
        message: error instanceof Error ? error.message : 'Unknown error',
      });
    }
  }

  return new CSVResult(rows, headers, errors);
}

// Export for Node.js
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { parseCSV, CSVResult };
}

