  assertEqual(result.rows[1].city, 'Paris', 'Should handle Unicode in data');
  assertEqual(result.rows[2].name, '李明', 'Should handle non-Latin Unicode');
});

// Test 36: Sum on filtered data
runTest('Sum on filtered data', () => {
  const csv = `product,category,price
A,Electronics,500
B,Clothing,50
C,Electronics,300
D,Clothing,75`;

  const result = parseCSV(csv);
  const electronics = result.filter((row) => row.category === 'Electronics');
  const total = electronics.sum('price');

  assertEqual(total, 800, 'Sum on filtered data should work correctly');
});

// Test 37: Average on filtered data
runTest('Average on filtered data', () => {
  const csv = `name,department,score
John,A,90
Jane,B,80
Bob,A,100
Alice,B,85`;

  const result = parseCSV(csv);
  const deptA = result.filter((row) => row.department === 'A');
  const avg = deptA.average('score');

  assertEqual(avg, 95, 'Average on filtered data should work correctly');
});

// Test 38: Complex CSV with all features
runTest('Complex CSV with all features', () => {
  const csv = `id,name,description,price,active
1,Product A,"A premium ""quality"" item",99.99,true
2,Product B,"Another, special item",49.50,false
3,Product C,"Item with
newline",null,true`;

  const result = parseCSV(csv);
  assertEqual(result.rows.length, 3, 'Should parse complex CSV');
  assertEqual(result.rows[0].description, 'A premium "quality" item', 'Should handle escaped quotes');
  assertEqual(result.rows[1].description, 'Another, special item', 'Should handle commas in quotes');
  assertEqual(result.rows[1].price, 49.5, 'Should handle float prices');
  assertEqual(result.rows[2].price, null, 'Should handle null values');
  assertEqual(result.errors.length, 0, 'Should have no errors');
});

// Test 39: Large dataset
runTest('Large dataset', () => {
  let csv = 'id,name,value\n';
  for (let i = 1; i <= 1000; i++) {
    csv += `${i},Item${i},${i * 10}\n`;
  }

