  assertEqual(result.rows.length, 1000, 'Should handle large datasets');
  assertEqual(result.rows[999].id, 1000, 'Last row should be correct');
  assertEqual(result.sum('value'), (1000 * 1001 * 10) / 2, 'Sum should work on large dataset');
});

// Test 40: Count on filtered data
runTest('Count on filtered data', () => {
