// {
//   name: 'Alice',
//   address: '123 Main St, Suite 100',  <- Comma preserved!
//   phone: '555-1234'
// }

console.log(result.rows[2].address);
// '789 Elm Rd, Building 3, Floor 2'  <- Multiple commas handled
```

### Escaped Quotes

```javascript
const csv = `id,description
1,"Product ""A"" - Premium Quality"
2,"The ""best"" choice for professionals"
3,"Save ""25%"" on bulk orders"`;

const result = parseCSV(csv);

console.log(result.rows[0].description);
// 'Product "A" - Premium Quality'

console.log(result.rows[1].description);
// 'The "best" choice for professionals'

console.log(result.rows[2].description);
// 'Save "25%" on bulk orders'
```

### Mixed Quotes and Commas

```javascript
const csv = `id,name,description,price
1,Product A,"Great item, ""premium"" quality",19.99
2,Product B,"Budget, but ""amazing"" value",9.99
3,Product C,"Professional grade, ""industrial"" strength",49.99`;

const result = parseCSV(csv);

console.log(result.rows[0]);
// {
//   id: 1,
//   name: 'Product A',
//   description: 'Great item, "premium" quality',
//   price: 19.99
// }
```

### Newlines in Quoted Fields

```javascript
const csv = `id,content
1,"First line
Second line
Third line"
2,"Single line"`;

const result = parseCSV(csv);

console.log(result.rows[0].content);
// 'First line\nSecond line\nThird line'

console.log(result.rows[1].content);
// 'Single line'
```

