## Filtering

### Single Filter

```javascript
const csv = `name,age,department,salary
Alice,28,Engineering,85000
Bob,35,Sales,75000
Charlie,42,Engineering,95000
Diana,31,Sales,72000
Eve,29,HR,65000`;

const result = parseCSV(csv);

// Filter by age
const over30 = result.filter(row => row.age > 30);
console.log(over30.rows.length);      // 2
console.log(over30.rows[0].name);     // 'Bob'

// Filter by department
const engineers = result.filter(row => row.department === 'Engineering');
console.log(engineers.rows.length);   // 2
console.log(engineers.rows[0].name);  // 'Alice'

// Filter by salary range
const highEarners = result.filter(row => row.salary > 80000);
console.log(highEarners.rows.length); // 2
```

### Chained Filters

```javascript
const csv = `name,age,department,salary
Alice,28,Engineering,85000
Bob,35,Sales,75000
Charlie,42,Engineering,95000
Diana,31,Sales,72000
Eve,29,HR,65000`;

const result = parseCSV(csv);

// Multiple filters
const filtered = result
  .filter(row => row.department === 'Engineering')
  .filter(row => row.age > 30)
  .filter(row => row.salary > 80000);

console.log(filtered.rows);
// [{ name: 'Charlie', age: 42, ... }]

// Filter with complex logic
const filtered2 = result
  .filter(row => {
    const isEngineer = row.department === 'Engineering';
    const isHighPaid = row.salary > 80000;
    return isEngineer && isHighPaid;
  });
```

### Filter with Index

```javascript
const csv = `name,position
Alice,Manager
Bob,Developer
Charlie,Designer
Diana,Tester
Eve,Analyst`;

const result = parseCSV(csv);

// Skip first row
const skipFirst = result.filter((row, index) => index > 0);
console.log(skipFirst.rows.length);   // 4

// Every other row
const everyOther = result.filter((row, index) => index % 2 === 0);
console.log(everyOther.rows.length);  // 3 (rows 0, 2, 4)

// Last 2 rows
const totalRows = result.rows.length;
const lastTwo = result.filter((row, index) => index >= totalRows - 2);
console.log(lastTwo.rows.length);     // 2
```

