console.log(`Exam 1 Average: ${avg1.toFixed(1)}`);
// Exam 1 Average: 87.5

const avg2 = result.average('exam2');
console.log(`Exam 2 Average: ${avg2.toFixed(1)}`);
// Exam 2 Average: 87.5

const avg3 = result.average('exam3');
console.log(`Exam 3 Average: ${avg3.toFixed(1)}`);
// Exam 3 Average: 89.0

// Average for specific student
