const result = parseCSV(csv);

// Group by department
const byDept = result.groupBy('department');

console.log(`Departments: ${Array.from(byDept.keys()).join(', ')}`);
// Departments: Engineering, Sales, HR

// Analyze each group
for (const [dept, rows] of byDept) {
  const total = rows.reduce((sum, r) => sum + r.salary, 0);
  const avg = total / rows.length;
  console.log(`${dept}: ${rows.length} people, $${avg.toFixed(0)} avg`);
}
// Engineering: 3 people, $86667 avg
// Sales: 2 people, $73500 avg
// HR: 1 people, $65000 avg

// Use grouped data
const engineeringTeam = byDept.get('Engineering');
console.log('Engineering Team:');
engineeringTeam.forEach(person => {
  console.log(`  - ${person.name}: $${person.salary}`);
});
// Engineering Team:
//   - Alice: $85000
//   - Charlie: $95000
//   - Frank: $80000
```

### GroupBy with Null Values

```javascript
const csv = `name,category,status
Item1,A,active
Item2,,inactive
Item3,A,active
Item4,,active
Item5,B,inactive
Item6,B,active`;

const result = parseCSV(csv);

const groups = result.groupBy('category');

console.log(`Groups: ${Array.from(groups.keys()).map(k => k || 'null').join(', ')}`);
// Groups: A, null, B

console.log(`Group A: ${groups.get('A').length} items`);
// Group A: 2 items

console.log(`Group null: ${groups.get(null).length} items`);
// Group null: 2 items

console.log(`Group B: ${groups.get('B').length} items`);
// Group B: 2 items
```

---

## Error Handling

### Malformed Rows

```javascript
const csv = `name,age,email
John,30,john@example.com
Jane,25,jane@example.com,extra_column
Bob,35`;  // Missing email

const result = parseCSV(csv);

console.log(`Valid rows: ${result.rows.length}`);
// Valid rows: 1

console.log(`Errors: ${result.errors.length}`);
// Errors: 2

// Examine errors
result.errors.forEach(err => {
  console.log(`Row ${err.row}: ${err.message}`);
});
// Row 2: Expected 3 columns, got 4
// Row 3: Expected 3 columns, got 2

// Process errors
const validData = result.rows;
console.log('Valid data processed:', validData);
// Valid data processed: [{ name: 'John', age: 30, email: 'john@example.com' }]
```

### Continue Processing Despite Errors

```javascript
const csv = `id,name,amount
1,Alice,1000
2,Bob,2000,extra
3,Charlie,3000
4,Diana`;  // Incomplete row

const result = parseCSV(csv);

// Can still use valid data
console.log(`Processed ${result.rows.length} valid rows`);
console.log(`Found ${result.errors.length} errors`);

// Calculate with valid data
if (result.rows.length > 0) {
  const total = result.sum('amount');
  const avg = result.average('amount');

  console.log(`Total: ${total}`);  // 6000
  console.log(`Average: ${avg}`);  // 2000
}

// Report issues
if (result.errors.length > 0) {
  console.warn('Data quality issues detected:');
  result.errors.forEach(err => {
    console.warn(`  - ${err.message}`);
  });
}
```

---

## Real-World Use Cases

### Sales Report

```javascript
const csv = `date,salesperson,product,quantity,unitPrice,region
2024-01-15,Alice,Widget,100,19.99,North
2024-01-15,Bob,Gadget,50,29.99,South
2024-01-16,Alice,Tool,200,9.99,North
2024-01-16,Charlie,Widget,75,19.99,East
2024-01-17,Bob,Device,25,99.00,South
2024-01-17,Diana,Widget,60,19.99,West`;

const result = parseCSV(csv);

// Calculate total revenue
const revenue = result.rows.reduce((sum, row) => {
  return sum + (row.quantity * row.unitPrice);
}, 0);
console.log(`Total Revenue: $${revenue.toFixed(2)}`);
// Total Revenue: $9318.25

// Sales by region
const byRegion = result.groupBy('region');
for (const [region, rows] of byRegion) {
  const regionRevenue = rows.reduce((sum, row) => {
    return sum + (row.quantity * row.unitPrice);
  }, 0);
  console.log(`${region}: $${regionRevenue.toFixed(2)}`);
}
// North: $3998.00
// South: $3998.50
// East: $1499.25
// West: $1199.40

// Top salesperson
const bySales = result.groupBy('salesperson');
let topSales = { name: '', total: 0 };
for (const [sales, rows] of bySales) {
  const total = rows.reduce((sum, row) => {
    return sum + (row.quantity * row.unitPrice);
  }, 0);
  if (total > topSales.total) {
    topSales = { name: sales, total };
  }
}
console.log(`Top Salesperson: ${topSales.name} ($${topSales.total.toFixed(2)})`);
// Top Salesperson: Alice ($3997.00)
```

### Student Grades

```javascript
const csv = `name,subject,score
Alice,Math,95
Alice,English,88
Alice,Science,92
Bob,Math,78
Bob,English,82
Bob,Science,85
Charlie,Math,92
Charlie,English,95
Charlie,Science,89`;

const result = parseCSV(csv);

// Average by student
const byStudent = result.groupBy('name');
console.log('Student Averages:');
for (const [student, grades] of byStudent) {
  const avg = grades.reduce((sum, g) => sum + g.score, 0) / grades.length;
  console.log(`  ${student}: ${avg.toFixed(1)}`);
}
// Student Averages:
//   Alice: 91.7
//   Bob: 81.7
//   Charlie: 92.0

// Average by subject
const bySubject = result.groupBy('subject');
console.log('\nSubject Averages:');
for (const [subject, scores] of bySubject) {
  const avg = scores.reduce((sum, s) => sum + s.score, 0) / scores.length;
  console.log(`  ${subject}: ${avg.toFixed(1)}`);
}
// Subject Averages:
//   Math: 88.3
//   English: 88.3
//   Science: 88.7

// Top scorer overall
let topStudent = { name: '', avg: 0 };
for (const [student, grades] of byStudent) {
  const avg = grades.reduce((sum, g) => sum + g.score, 0) / grades.length;
  if (avg > topStudent.avg) {
    topStudent = { name: student, avg };
  }
}
console.log(`\nTop Student: ${topStudent.name} (${topStudent.avg.toFixed(1)} avg)`);
// Top Student: Charlie (92.0 avg)
```

### Inventory Management

```javascript
const csv = `productId,name,quantity,reorderLevel,unitCost
1,Widget,45,50,19.99
2,Gadget,8,20,29.99
3,Tool,150,100,9.99
4,Device,5,10,99.00
5,Component,200,100,4.99`;

const result = parseCSV(csv);

// Items below reorder level
const lowStock = result.filter(row => row.quantity < row.reorderLevel);
console.log('Low Stock Items:');
lowStock.rows.forEach(item => {
  const shortage = item.reorderLevel - item.quantity;
  const reorderCost = shortage * item.unitCost;
  console.log(`  ${item.name}: need ${shortage} units ($${reorderCost.toFixed(2)})`);
});
// Low Stock Items:
//   Gadget: need 12 units ($359.88)
//   Device: need 5 units ($495.00)

// Total inventory value
const totalValue = result.rows.reduce((sum, row) => {
  return sum + (row.quantity * row.unitCost);
}, 0);
console.log(`\nTotal Inventory Value: $${totalValue.toFixed(2)}`);
// Total Inventory Value: $4449.35

// Reorder requirements
const reorderNeeded = lowStock.rows.reduce((sum, row) => {
  return sum + ((row.reorderLevel - row.quantity) * row.unitCost);
}, 0);
console.log(`Reorder Cost: $${reorderNeeded.toFixed(2)}`);
// Reorder Cost: $854.88
```

---

These examples demonstrate the full power and flexibility of the CSV parser library!

